rust-sqlx.query_fn:
pub async fn upsert_user(pool: &sqlx::PgPool, name: &str, email: &str) -> Result<UpsertUserRow, sqlx::Error> {
    sqlx::query_as!(UpsertUserRow, "INSERT INTO users (name, email) VALUES ($1, $2) ON CONFLICT (email) DO UPDATE SET name = EXCLUDED.name RETURNING *", name, email)
        .fetch_one(pool)
        .await
}

